import { useState } from "react";
import axios from "axios";

function App() {
  const [email, setEmail] = useState("");
  const [apiKey, setApiKey] = useState("");
  const [usage, setUsage] = useState([]);
  const [response, setResponse] = useState("");
  const [loading, setLoading] = useState(false);

  const API = "http://localhost:5000";

  const signup = async () => {
    setLoading(true);
    const res = await axios.post(`${API}/auth/signup`, { email });
    setApiKey(res.data.apiKey);
    setLoading(false);
  };

  const callAPI = async () => {
    setLoading(true);
    const res = await axios.get(
      `${API}/proxy?url=https://jsonplaceholder.typicode.com/todos/1&apiKey=${apiKey}`
    );
    setResponse(JSON.stringify(res.data, null, 2));
    setLoading(false);
  };

  const fetchUsage = async () => {
    const res = await axios.get(`${API}/usage/${apiKey}`);
    setUsage(res.data);
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>🚀 MeterFlow Dashboard</h1>

      {/* Signup Card */}
      <div style={styles.card}>
        <h2>Create Account</h2>
        <input
          style={styles.input}
          placeholder="Enter Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />
        <button style={styles.button} onClick={signup}>
          {loading ? "Loading..." : "Generate API Key"}
        </button>

        {apiKey && (
          <>
            <p><b>Your API Key:</b></p>
            <code style={styles.code}>{apiKey}</code>
          </>
        )}
      </div>

      {/* Actions */}
      {apiKey && (
        <div style={styles.card}>
          <h2>Test API Gateway</h2>
          <button style={styles.button} onClick={callAPI}>
            Call External API
          </button>
          <button style={styles.buttonSecondary} onClick={fetchUsage}>
            Load Usage Logs
          </button>
        </div>
      )}

      {/* Response */}
      {response && (
        <div style={styles.card}>
          <h3>API Response</h3>
          <pre style={styles.pre}>{response}</pre>
        </div>
      )}

      {/* Usage Logs */}
      {usage.length > 0 && (
        <div style={styles.card}>
          <h3>Usage Logs</h3>
          <table style={styles.table}>
            <thead>
              <tr>
                <th>URL</th>
                <th>Status</th>
                <th>Time</th>
              </tr>
            </thead>
            <tbody>
              {usage.map((u, i) => (
                <tr key={i}>
                  <td>{u.url}</td>
                  <td>{u.status}</td>
                  <td>{new Date(u.timestamp).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: {
    fontFamily: "Arial",
    padding: "40px",
    background: "#f4f6f8",
    minHeight: "100vh",
  },
  title: {
    marginBottom: "20px",
  },
  card: {
    background: "white",
    padding: "20px",
    marginBottom: "20px",
    borderRadius: "10px",
    boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
  },
  input: {
    padding: "10px",
    width: "250px",
    marginRight: "10px",
  },
  button: {
    padding: "10px 15px",
    background: "#007bff",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
    marginRight: "10px",
  },
  buttonSecondary: {
    padding: "10px 15px",
    background: "#28a745",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
  code: {
    background: "#eee",
    padding: "8px",
    display: "block",
    marginTop: "10px",
  },
  pre: {
    background: "#111",
    color: "#0f0",
    padding: "15px",
    borderRadius: "5px",
    overflowX: "auto",
  },
  table: {
    width: "100%",
    borderCollapse: "collapse",
  },
};

export default App;
